.diff-viewer-page{
background:#f8fafc;
min-height:100vh;
display:flex;
flex-direction:column;
}

/* HEADER */

.diff-header-section{
padding:20px 36px;
background:#ffffff;
border-bottom:1px solid #e2e8f0;
position:sticky;
top:0;
z-index:100;

display:flex;
flex-direction:column;
gap:10px;
}

.diff-title-row{
display:flex;
align-items:center;
gap:12px;
margin-top:4px;
}

.review-layout{
display:flex;
height:calc(100vh - 120px);
overflow:hidden;
}

/* LEFT PANEL */

.left-panel{
width:320px;
background:#ffffff;
border-right:1px solid #e2e8f0;
display:flex;
flex-direction:column;
}

.badge{
background:#dcfce7;
color:#15803d;
font-weight:600;
padding:4px 10px;
border-radius:20px;
font-size:12px;
}

/* ISSUE LIST */

.issue-list{
overflow:auto;
flex:1;
}

.file-group{
border-bottom:1px solid #f1f5f9;
}

.file-header{
display:flex;
align-items:center;
gap:8px;
padding:10px 14px;
font-size:13px;
font-weight:600;
cursor:pointer;
}

.file-header:hover{
background:#f8fafc;
}

.file-name{
flex:1;
color:#334155;
}

/* ISSUE */

.issue-item{
display:flex;
gap:10px;
padding:10px 14px;
border-left:3px solid transparent;
}

.issue-item:hover{
background:#f8fafc;
}

.issue-content{
flex:1;
}

.issue-message{
font-size:13px;
font-weight:600;
margin:0;
}

.issue-meta{
display:flex;
gap:8px;
margin-top:4px;
font-size:11px;
color:#64748b;
}

/* SEVERITY */

.severity{
padding:2px 8px;
border-radius:6px;
font-weight:600;
}

.severity.critical{
background:#fee2e2;
color:#b91c1c;
}

.severity.major{
background:#fef3c7;
color:#92400e;
}

.severity.minor{
background:#e0f2fe;
color:#0369a1;
}

/* RIGHT DIFF AREA */

.diff-content{
flex:1;
display:flex;
flex-direction:column;
background:#f8fafc;
overflow:hidden;
}

.diff-container{
display:flex;
gap:16px;
padding:20px;
overflow:auto;
flex:1;
}

/* CODE COLUMNS */

.diff-column{
flex:1;
background:white;
border:1px solid #e2e8f0;
border-radius:8px;
overflow:hidden;
display:flex;
flex-direction:column;
min-width:0;
}

.diff-header{
padding:10px 14px;
font-weight:700;
font-size:12px;
letter-spacing:0.5px;
}

.diff-header.red{
background:#fee2e2;
color:#ef4444;
}

.diff-header.green{
background:#dcfce7;
color:#16a34a;
}

/* CODE BLOCK */

.code-block{
flex:1;
overflow:auto;
font-family:"JetBrains Mono","Fira Code",monospace;
font-size:13px;
}

/* CODE LINES */

.code-line{
display:flex;
width:100%;
}

.line-number{
width:55px;
background:#f1f5f9;
color:#64748b;
text-align:right;
padding:4px 8px;
font-size:11px;
user-select:none;
border-right:1px solid #e2e8f0;
flex-shrink:0;
}

.line-code{
margin:0;
padding:4px 10px;
white-space:pre;
color:#1e293b;
flex:1;
}

/* DIFF COLORS */

.code-line.removed{
background:#fff1f2;
border-left:3px solid #ef4444;
}

.code-line.added{
background:#f0fdf4;
border-left:3px solid #16a34a;
}

.code-line.modified{
background:#fef9c3;
border-left:3px solid #eab308;
}

/* BUTTON ROW */

.btn-row{
display:flex;
gap:10px;
}

/* BREADCRUMBS */

.custom-breadcrumbs{
display:flex;
align-items:center;
font-size:13px;
font-weight:500;
margin-bottom:10px;
color:#64748b;
}

.custom-breadcrumbs a{
color:#475569;
text-decoration:none;
padding:4px 8px;
border-radius:6px;
transition:all 0.15s ease;
cursor:pointer;
}

.custom-breadcrumbs a:hover{
background:#f1f5f9;
color:#0f172a;
}

.custom-breadcrumbs p{
margin:0;
padding:4px 8px;
font-weight:600;
color:#0f172a;
}

.custom-breadcrumbs svg{
color:#94a3b8;
margin:0 4px;
}
